4.2 Sécurisation foncière
La sécurisation foncière est un enjeu majeur à Madagascar. Les ménages peuvent détenir un titre foncier, un certificat foncier (délivré par le guichet foncier communal), ou divers documents informels.


Code
sec_data &lt;- fr30_data |&gt;
  mutate(
    Titre = if_else(fr30j == 1, "Oui", "Non"),
    Certificat = if_else(fr30l == 1, "Oui", "Non")
  )

titre_pct &lt;- sec_data |&gt;
  filter(!is.na(Titre)) |&gt;
  count(Observatory, Titre) |&gt;
  mutate(pct = round(n / sum(n) * 100, 1), .by = Observatory) |&gt;
  filter(Titre == "Oui") |&gt;
  select(Observatory, pct) |&gt;
  pivot_wider(names_from = Observatory, values_from = pct) |&gt;
  mutate(Document = "Titre foncier", .before = 1)

cert_pct &lt;- sec_data |&gt;
  filter(!is.na(Certificat)) |&gt;
  count(Observatory, Certificat) |&gt;
  mutate(pct = round(n / sum(n) * 100, 1), .by = Observatory) |&gt;
  filter(Certificat == "Oui") |&gt;
  select(Observatory, pct) |&gt;
  pivot_wider(names_from = Observatory, values_from = pct) |&gt;
  mutate(Document = "Certificat foncier", .before = 1)

bind_rows(titre_pct, cert_pct) |&gt;
  gt() |&gt;
  tab_header(title = "% des parcelles disposant d'un document de sécurisation") |&gt;
  cols_label(Alaotra = "Alaotra (%)", Marovoay = "Marovoay (%)")




